Greedy insertion with look-ahead penalty for time-window violations and distance-based tie-breaking, using a composite score combining marginal cost increase, temporal slack reduction, and geographic proximity to route ends.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		type candidate struct {
			idx       int
			score     float64
			costDelta float64
		}
		var bestCandidate *candidate

		existingCount := dispatch.AssignsLen
		for i := 0; i < existingCount; i++ {
			assign := &dispatch.Assigns[i]
			savedCost := assign.Cost
			savedStations := assign.StationCurrent // shallow copy sufficient for rollback marker

			ok := assign.AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 || newCost > 1e17 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}
			costDelta := newCost - savedCost
			timePenalty := 0.0
			stationCurrentAfter := assign.StationCurrent
			if ori.TimeStart > stationCurrentAfter.TimeEnd || des.TimeStart > stationCurrentAfter.TimeEnd {
				timePenalty += 500.0
			}
			slackReduction := 0.0
			if stationCurrentAfter.TimeEnd > 0 && savedStations.TimeEnd > 0 {
				slackReduction = float64(savedStations.TimeEnd - stationCurrentAfter.TimeEnd)
				if slackReduction < 0 {
					slackReduction = -slackReduction * 10.0
				}
			}
			proximityBonus := -cal_dis(stationCurrentAfter, ori) * 0.3
			compositeScore := costDelta*1.0 + timePenalty*1.5 + slackReduction*0.8 + proximityBonus*1.0
			if bestCandidate == nil || compositeScore < bestCandidate.score {
				bestCandidate = &candidate{idx: i, score: compositeScore, costDelta: costDelta}
			}
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		inserted := false
		if bestCandidate != nil {
			assign := &dispatch.Assigns[bestCandidate.idx]
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				inserted = true
			}
		}

		if !inserted {
			fallbackCandidates := make([]int, 0, MAXASSIGNS)
			for i := 0; i < MAXASSIGNS; i++ {
				fallbackCandidates = append(fallbackCandidates, i)
			}
			for _, i := range fallbackCandidates {
				assign := &dispatch.Assigns[i]
				if assign.AddShip(shipID, ori, des) {
					assign.GenRoute()
					if i >= dispatch.AssignsLen {
						dispatch.AssignsLen = i + 1
					}
					inserted = true
					break
				}
			}
		}

		if !inserted {
			for i := 0; i < MAXASSIGNS; i++ {
				assign := &dispatch.Assigns[i]
				oldLen := dispatch.AssignsLen
				if i >= oldLen {
					dispatch.AssignsLen = i + 1
				}
				if assign.AddShip(shipID, ori, des) {
					assign.GenRoute()
					inserted = true
					break
				} else if i >= oldLen {
					dispatch.AssignsLen = oldLen
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

